import React from 'react';
import type { CSSProperties } from 'react';
import { COMPANY_FIELD_LABEL } from '../../utils/companyField';

export const CatalogCompanyTh: React.FC = () => (
  <th>{COMPANY_FIELD_LABEL}</th>
);

export interface CatalogCompanyTdProps {
  /**
   * Resolved company display label.
   * Pass `row.companyName` — BE joins PlatformCompanies and returns this field.
   * For create form: derive `sessionCompanyName = items[0]?.companyName`.
   */
  label?: string;
  style?: CSSProperties;
}

/** Renders company label cell. Use `row.companyName` from BE response — never call
 * useCompanyLabelMap() anywhere in the MFE. */
export const CatalogCompanyTd: React.FC<CatalogCompanyTdProps> = ({ label, style }) => (
  <td style={style}>{label ?? '—'}</td>
);
