import React, { useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { isStandalone } from '../dev/isStandalone';

/**
 * Sync window.location <-> MemoryRouter.
 *
 * - Normal MFE mode: listen window events -> navigate() inside MemoryRouter.
 * - Standalone mode: additionally reflect MemoryRouter navigation back to address bar
 *   via replaceState (keeps deep-link + F5 behavior correct).
 */
export const MemoryRouterSync: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const locationRef = useRef(location);
  locationRef.current = location;

  const syncingFromWindowRef = useRef(false);

  useEffect(() => {
    const syncFromWindow = () => {
      const nextPath =
        (window.location.pathname || '/') + (window.location.search || '');
      const currentPath =
        (locationRef.current.pathname || '/') + (locationRef.current.search || '');

      if (nextPath === currentPath) return;

      syncingFromWindowRef.current = true;
      navigate(nextPath, { replace: true });
      queueMicrotask(() => {
        syncingFromWindowRef.current = false;
      });
    };

    const handlePopState = () => syncFromWindow();
    const handleSingleSpaRoutingEvent = () => syncFromWindow();

    window.addEventListener('popstate', handlePopState);
    window.addEventListener('single-spa:routing-event', handleSingleSpaRoutingEvent as any);

    return () => {
      window.removeEventListener('popstate', handlePopState);
      window.removeEventListener('single-spa:routing-event', handleSingleSpaRoutingEvent as any);
    };
  }, [navigate]);

  useEffect(() => {
    if (!isStandalone) return;
    if (syncingFromWindowRef.current) return;

    const nextUrl = location.pathname + location.search;
    const currentUrl = window.location.pathname + window.location.search;
    if (nextUrl === currentUrl) return;

    window.history.replaceState(null, '', nextUrl);
  }, [location.pathname, location.search]);

  return null;
};

export default MemoryRouterSync;
