import { apiClient, unwrap, type BffResponse } from '../api';

const BASE = '/master/code-replace';

export type CodeReplaceJobLine = {
  sortOrder: number;
  phase: string;
  tableName: string;
  entityLabel: string;
  columnName: string;
  keyDescription?: string;
  estimatedCount: number;
  appliedCount?: number;
  errorMessage?: string;
};

export type CodeReplaceJob = {
  id: string;
  catalogKind: string;
  oldCode: string;
  newCode: string;
  mergeIfExists?: boolean;
  mode: string;
  status: string;
  errorMessage?: string;
  totalAffectedCount: number;
  createdAt: string;
  startedAt?: string;
  completedAt?: string;
  lines: CodeReplaceJobLine[];
};

export type CodeReplacePending = {
  jobId: string;
  oldCode: string;
  newCode: string;
  status: string;
  errorMessage?: string;
  updatedAt: string;
};

export type CodeReplaceLookupBlocked = {
  blocked: boolean;
  jobId?: string;
  reason?: string;
};

export type CodeUsageImpact = {
  tableName: string;
  entityLabel: string;
  estimatedCount: number;
};

export async function previewCodeReplace(body: {
  catalogKind: string;
  oldCode: string;
  newCode: string;
  mergeIfExists?: boolean;
}): Promise<CodeReplaceJob> {
  const res = await apiClient.post<BffResponse<CodeReplaceJob>>(`${BASE}/preview`, body);
  return unwrap(res)!;
}

export async function confirmCodeReplace(body: {
  catalogKind: string;
  oldCode: string;
  newCode: string;
  mergeIfExists?: boolean;
}): Promise<CodeReplaceJob> {
  const res = await apiClient.post<BffResponse<CodeReplaceJob>>(`${BASE}/confirm`, body);
  return unwrap(res)!;
}

export async function applyCodeReplaceJob(jobId: string): Promise<CodeReplaceJob> {
  const res = await apiClient.post<BffResponse<CodeReplaceJob>>(`${BASE}/${jobId}/apply`, {});
  return unwrap(res)!;
}

export async function getCodeReplaceJob(jobId: string): Promise<CodeReplaceJob> {
  const res = await apiClient.get<BffResponse<CodeReplaceJob>>(`${BASE}/jobs/${jobId}`);
  return unwrap(res)!;
}

export async function getCodeReplacePending(catalogKind: string): Promise<CodeReplacePending[]> {
  const res = await apiClient.get<BffResponse<CodeReplacePending[]>>(
    `${BASE}/pending?catalogKind=${encodeURIComponent(catalogKind)}`,
  );
  return unwrap(res) ?? [];
}

export async function isCodeReplaceLookupBlocked(
  catalogKind: string,
  code: string,
): Promise<CodeReplaceLookupBlocked> {
  const qs = new URLSearchParams({ catalogKind, code });
  const res = await apiClient.get<BffResponse<CodeReplaceLookupBlocked>>(
    `${BASE}/lookup-blocked?${qs.toString()}`,
  );
  return unwrap(res) ?? { blocked: false };
}

export async function fetchCodeUsageImpact(
  catalogKind: string,
  oldCode: string,
  newCode: string,
): Promise<CodeUsageImpact[]> {
  const qs = new URLSearchParams({ newCode });
  const res = await apiClient.get<BffResponse<CodeUsageImpact[]>>(
    `/master/${encodeURIComponent(catalogKind)}/${encodeURIComponent(oldCode)}/usage-impact?${qs.toString()}`,
  );
  const rows = unwrap(res) ?? [];
  return rows.map(r => ({
    tableName: r.tableName,
    entityLabel: r.entityLabel,
    estimatedCount: r.estimatedCount,
  }));
}
