import { useLayoutEffect, useState } from 'react';
import {
  companyService,
  getActiveCompanyId,
  normCompanyCode,
  setActiveCompanyId,
} from '@linm-soft-org/linm-web-common-components';

/**
 * Dev/standalone: align stored X-Company-Id with GET /companies/active-list.
 * After Docker DB reset only LINM may exist while localStorage still has FM06 → API 400.
 */
export function useSyncActiveCompanyOnBoot(): boolean {
  const [ready, setReady] = useState(!import.meta.env.DEV);

  useLayoutEffect(() => {
    if (!import.meta.env.DEV) return;

    let cancelled = false;

    companyService
      .getActiveList()
      .then((list) => {
        if (cancelled || list.length === 0) return;

        const validIds = new Set(list.map((c) => normCompanyCode(c.id)));
        const stored = getActiveCompanyId();
        if (stored && validIds.has(normCompanyCode(stored))) return;

        setActiveCompanyId(list[0].id);
      })
      .catch(() => undefined)
      .finally(() => {
        if (!cancelled) setReady(true);
      });

    return () => {
      cancelled = true;
    };
  }, []);

  return ready;
}
